mapper.select:
SELECT con.game_one_id, con.game_two_id, con.venue_code, con.id, con.status, cla_info.directory_name as gameOneName, con.float_name_i18n_code, con.logo_icon_i18n_code, cla_info.model, con.medium_icon_i18n_code, con.creator, con.created_time, con.updater, con.updated_time FROM game_one_float_config con INNER JOIN game_one_class_info cla_info ON cla_info.id = con.game_one_id WHERE con.site_code = #{siteCode}
AND con.game_one_id = #{gameOneId}
AND con.status = #{status} /* AND cla_info.status = #{status}*/
/*AND con.status = 1*/ ORDER BY CASE WHEN con.status = 1 THEN 0 ELSE 1 END, con.created_time DESC
